content.text:
# Confirm the region pair for your target before committing
az account list-locations \
  --query "[?name=='northeurope'].{Region:name, PairedWith:metadata.pairedRegion[0].name}" \
  --output json
# {"Region": "northeurope", "PairedWith": "westeurope"}

# Automate region-pair validation in Terraform
data "azurerm_location" "primary" {
  location = var.primary_region
}
locals {
  paired_region = data.azurerm_location.primary.paired_region_location[0]
}
output "dr_target" {
  value = local.paired_region
}

# Terraform: validate that only approved regions are used
variable "location" {
  type        = string
  description = "Azure region for deployment"

  validation {
    condition = contains([
      "northeurope",
      "westeurope",
      "uksouth",
      "ukwest"
    ], var.location)
    error_message = "Location must be an EU/UK geography region for GDPR compliance. Provided: ${var.location}"
  }
}

variable "dr_location" {
  type        = string
  description = "Azure region for disaster recovery (must be the region pair of location)"

  validation {
    condition = (
      (var.location == "northeurope" && var.dr_location == "westeurope") ||
      (var.location == "westeurope"  && var.dr_location == "northeurope") ||
      (var.location == "uksouth"     && var.dr_location == "ukwest") ||
      (var.location == "ukwest"      && var.dr_location == "uksouth")
    )
    error_message = "dr_location must be the region pair of location."
  }
}
